const BRAND_ALIASES = {
  "HOND": "Honda",
  "MOTO MORINI": "Moto Morini",
  "MOTOMORINI": "Moto Morini",
  "HARLEY DAVIDSON": "Harley-Davidson",
  "HARLEY-DAVIDSON": "Harley-Davidson",
};

function normalizeSpace(value) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function normalizeBrandDisplay(brand) {
  const raw = normalizeSpace(brand);
  const upper = raw.toUpperCase();
  return BRAND_ALIASES[upper] || raw;
}

function normalizeModelDisplay(model) {
  return normalizeSpace(model)
    .replace(/\([^)]*\)/g, "")
    .replace(/\b(19|20)\d{2}\b/g, "")
    .replace(/\bautomatic\b/gi, "")
    .replace(/\btransmission\b/gi, "")
    .replace(/\s+/g, " ")
    .trim();
}

export function buildRentalHeroImageId(brand, model) {
  return `${normalizeBrandDisplay(brand)}-${normalizeModelDisplay(model)}`
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "");
}

